import{_ as e,o as a,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const f=JSON.parse('{"title":"北京自然博物馆","description":"","frontmatter":{},"headers":[],"relativePath":"museums/natural-history.md","filePath":"museums/natural-history.md","lastUpdated":null}'),n={name:"museums/natural-history.md"};function o(i,t,s,d,h,g){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="北京自然博物馆" tabindex="-1">北京自然博物馆 <a class="header-anchor" href="#北京自然博物馆" aria-label="Permalink to &quot;北京自然博物馆&quot;">​</a></h1><blockquote><p>&quot;探索自然奥秘，恐龙世界精彩。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>北京自然博物馆位于北京市东城区，是中国唯一的国家级大型自然博物馆。博物馆以生物进化为主线，展示了生物的起源、演化以及人与自然的关系。自然博物馆以恐龙化石闻名，是亲子游的热门目的地。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">9:00-17:00（周一闭馆）</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">免费（需预约）</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">3-4小时</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">四季皆宜</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁8号线天桥站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市东城区天桥南大街126号</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="创建" tabindex="-1">创建 <a class="header-anchor" href="#创建" aria-label="Permalink to &quot;创建&quot;">​</a></h3><p>北京自然博物馆前身是中央自然博物馆筹备处，筹建于1951年。1959年，新馆建成，1962年正式命名为&quot;北京自然博物馆&quot;。</p><h3 id="发展" tabindex="-1">发展 <a class="header-anchor" href="#发展" aria-label="Permalink to &quot;发展&quot;">​</a></h3><p>1980年代，博物馆进行了大规模改造，增加了恐龙展厅。2000年代，博物馆再次改造，增加了&quot;恐龙公园&quot;等新展览。</p><h2 id="建筑特色" tabindex="-1">建筑特色 <a class="header-anchor" href="#建筑特色" aria-label="Permalink to &quot;建筑特色&quot;">​</a></h2><h3 id="外观" tabindex="-1">外观 <a class="header-anchor" href="#外观" aria-label="Permalink to &quot;外观&quot;">​</a></h3><p>北京自然博物馆建筑呈对称布局，正面有高大的柱廊，庄重大气。</p><h3 id="内部" tabindex="-1">内部 <a class="header-anchor" href="#内部" aria-label="Permalink to &quot;内部&quot;">​</a></h3><p>博物馆内部有多个展厅，布局合理，参观路线清晰。</p><h2 id="常设展览" tabindex="-1">常设展览 <a class="header-anchor" href="#常设展览" aria-label="Permalink to &quot;常设展览&quot;">​</a></h2><h3 id="古爬行动物厅-恐龙世界" tabindex="-1">古爬行动物厅（恐龙世界） <a class="header-anchor" href="#古爬行动物厅-恐龙世界" aria-label="Permalink to &quot;古爬行动物厅（恐龙世界）&quot;">​</a></h3><p>这是自然博物馆最热门的展厅，展示了各种恐龙化石。</p><h4 id="恐龙化石" tabindex="-1">恐龙化石 <a class="header-anchor" href="#恐龙化石" aria-label="Permalink to &quot;恐龙化石&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">恐龙</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>马门溪龙</strong></td><td style="text-align:left;">中国最大的恐龙之一，长26米</td></tr><tr><td style="text-align:left;"><strong>许氏禄丰龙</strong></td><td style="text-align:left;">中国第一具装架的恐龙化石</td></tr><tr><td style="text-align:left;"><strong>沱江龙</strong></td><td style="text-align:left;">剑龙类恐龙</td></tr><tr><td style="text-align:left;"><strong>霸王龙</strong></td><td style="text-align:left;">肉食性恐龙</td></tr><tr><td style="text-align:left;"><strong>三角龙</strong></td><td style="text-align:left;">草食性恐龙</td></tr></tbody></table><h4 id="恐龙公园" tabindex="-1">恐龙公园 <a class="header-anchor" href="#恐龙公园" aria-label="Permalink to &quot;恐龙公园&quot;">​</a></h4><p>展厅内复原了恐龙生活的场景，有电子恐龙模型，可以动、可以叫，深受小朋友喜爱。</p><h3 id="古哺乳动物厅" tabindex="-1">古哺乳动物厅 <a class="header-anchor" href="#古哺乳动物厅" aria-label="Permalink to &quot;古哺乳动物厅&quot;">​</a></h3><p>展示古代哺乳动物化石，包括：</p><ul><li><strong>黄河象</strong>：中国最大的古象化石</li><li><strong>猛犸象</strong>：史前巨兽</li><li><strong>披毛犀</strong>：冰河时期的犀牛</li><li><strong>剑齿虎</strong>：史前猫科动物</li></ul><h3 id="无脊椎动物厅" tabindex="-1">无脊椎动物厅 <a class="header-anchor" href="#无脊椎动物厅" aria-label="Permalink to &quot;无脊椎动物厅&quot;">​</a></h3><p>展示各种无脊椎动物，包括昆虫、贝类、珊瑚等。</p><h3 id="植物世界厅" tabindex="-1">植物世界厅 <a class="header-anchor" href="#植物世界厅" aria-label="Permalink to &quot;植物世界厅&quot;">​</a></h3><p>展示植物的起源和演化，从藻类到被子植物。</p><h3 id="人之由来厅" tabindex="-1">人之由来厅 <a class="header-anchor" href="#人之由来厅" aria-label="Permalink to &quot;人之由来厅&quot;">​</a></h3><p>展示人类的起源和演化，从猿人到现代人。</p><h4 id="人类进化" tabindex="-1">人类进化 <a class="header-anchor" href="#人类进化" aria-label="Permalink to &quot;人类进化&quot;">​</a></h4><ul><li><strong>古猿</strong>：人类的祖先</li><li><strong>直立人</strong>：北京猿人、元谋人等</li><li><strong>智人</strong>：现代人的直接祖先</li></ul><h3 id="动物陈列厅" tabindex="-1">动物陈列厅 <a class="header-anchor" href="#动物陈列厅" aria-label="Permalink to &quot;动物陈列厅&quot;">​</a></h3><p>展示各种动物标本，包括：</p><ul><li><strong>哺乳动物</strong>：狮子、老虎、熊等</li><li><strong>鸟类</strong>：各种鸟类标本</li><li><strong>爬行动物</strong>：蛇、龟、鳄鱼等</li><li><strong>两栖动物</strong>：蛙、蟾蜍等</li><li><strong>鱼类</strong>：各种鱼类标本</li></ul><h3 id="神奇的非洲厅" tabindex="-1">神奇的非洲厅 <a class="header-anchor" href="#神奇的非洲厅" aria-label="Permalink to &quot;神奇的非洲厅&quot;">​</a></h3><p>这是自然博物馆的特色展厅，展示了非洲的自然环境和动物。</p><h4 id="展厅特色" tabindex="-1">展厅特色 <a class="header-anchor" href="#展厅特色" aria-label="Permalink to &quot;展厅特色&quot;">​</a></h4><ul><li><strong>非洲草原</strong>：复原非洲草原场景</li><li><strong>非洲动物</strong>：狮子、大象、长颈鹿、斑马等</li><li><strong>非洲部落</strong>：非洲原始部落文化</li></ul><h2 id="珍贵化石" tabindex="-1">珍贵化石 <a class="header-anchor" href="#珍贵化石" aria-label="Permalink to &quot;珍贵化石&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">化石</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>马门溪龙化石</strong></td><td style="text-align:left;">中国最大的恐龙化石之一</td></tr><tr><td style="text-align:left;"><strong>许氏禄丰龙</strong></td><td style="text-align:left;">中国第一具装架的恐龙化石</td></tr><tr><td style="text-align:left;"><strong>黄河象化石</strong></td><td style="text-align:left;">中国最大的古象化石</td></tr><tr><td style="text-align:left;"><strong>北京猿人头盖骨</strong></td><td style="text-align:left;">复制品，原件失踪</td></tr><tr><td style="text-align:left;"><strong>猛犸象化石</strong></td><td style="text-align:left;">史前巨兽</td></tr></tbody></table><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="预约须知" tabindex="-1">预约须知 <a class="header-anchor" href="#预约须知" aria-label="Permalink to &quot;预约须知&quot;">​</a></h3><ol><li><strong>提前预约</strong>：必须提前在官网或微信预约</li><li><strong>实名制</strong>：需携带身份证</li><li><strong>周一闭馆</strong>：注意开放时间</li><li><strong>票源紧张</strong>：尤其节假日，需提前抢</li></ol><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>经典路线（约3-4小时）</strong>：</p><p>恐龙世界 → 古哺乳动物厅 → 神奇的非洲 → 人之由来 → 动物陈列 → 植物世界 → 无脊椎动物</p><p><strong>亲子路线</strong>：</p><p>恐龙世界（重点） → 神奇的非洲 → 动物陈列 → 人之由来</p><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">站点</th></tr></thead><tbody><tr><td style="text-align:left;">地铁</td><td style="text-align:left;">8号线天桥站B口</td></tr><tr><td style="text-align:left;">公交</td><td style="text-align:left;">7路、17路、20路等天桥站</td></tr><tr><td style="text-align:left;">步行</td><td style="text-align:left;">从天坛公园步行约15分钟</td></tr></tbody></table><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>提前预约</strong>：票源紧张，务必提前预约</li><li><strong>恐龙世界</strong>：最热门展厅，建议先看</li><li><strong>讲解服务</strong>：可租借语音导览</li><li><strong>餐饮</strong>：馆内有餐厅</li><li><strong>亲子游</strong>：非常适合带孩子参观</li><li><strong>避开高峰</strong>：周末人极多，建议工作日</li><li><strong>结合游览</strong>：可与天坛公园一起游览</li></ol><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">天坛公园</td><td style="text-align:center;">步行15分钟</td><td style="text-align:left;">明清祭天圣地</td></tr><tr><td style="text-align:left;">天桥剧场</td><td style="text-align:center;">紧邻</td><td style="text-align:left;">杂技表演</td></tr><tr><td style="text-align:left;">前门大街</td><td style="text-align:center;">步行20分钟</td><td style="text-align:left;">老北京商业街</td></tr><tr><td style="text-align:left;">大栅栏</td><td style="text-align:center;">步行20分钟</td><td style="text-align:left;">老北京商业街</td></tr></tbody></table><h2 id="教育意义" tabindex="-1">教育意义 <a class="header-anchor" href="#教育意义" aria-label="Permalink to &quot;教育意义&quot;">​</a></h2><p>北京自然博物馆是国家级科普教育基地，承担着向青少年普及自然科学知识的重要使命。</p><p>博物馆通过丰富的展品和生动的展览，让小朋友们了解生命的起源和演化，激发对自然科学的兴趣。</p><hr><p><strong>📍 地址</strong>：北京市东城区天桥南大街126号 <strong>📞 电话</strong>：010-67024435 <strong>🌐 官网</strong>：<a href="http://www.bmnh.org.cn" target="_blank" rel="noreferrer">www.bmnh.org.cn</a><strong>📱 预约</strong>：关注&quot;北京自然博物馆&quot;微信公众号预约</p>',62)])])}const u=e(n,[["render",o]]);export{f as __pageData,u as default};
